# Enable anomaly detection alert for a subscription (via portal or REST)
# The anomaly alert rule is created at subscription scope
az rest --method PUT \
  --url "https://management.azure.com/subscriptions/<subscription-id>/providers/Microsoft.CostManagement/scheduledActions/anomaly-detection-daily?api-version=2023-11-01" \
  --body '{
    "kind": "InsightAlert",
    "properties": {
      "displayName": "Daily Anomaly Alert",
      "scope": "/subscriptions/<subscription-id>",
      "status": "Enabled",
      "schedule": {
        "frequency": "Daily",
        "hourOfDay": 8
      },
      "notification": {
        "to": ["cloudops@contoso.com"],
        "subject": "Azure Cost Anomaly Detected"
      }
    }
  }'

import requests
from azure.identity import DefaultAzureCredential

credential = DefaultAzureCredential()
token = credential.get_token("https://management.azure.com/.default").token
headers = {
    "Authorization": f"Bearer {token}",
    "Content-Type": "application/json"
}

subscription_id = "<subscription-id>"
scope = f"/subscriptions/{subscription_id}"

# Create anomaly alert (InsightAlert) via scheduled action
url = (
    f"https://management.azure.com{scope}/"
    f"providers/Microsoft.CostManagement/scheduledActions/anomaly-daily"
    f"?api-version=2023-11-01"
)

body = {
    "kind": "InsightAlert",
    "properties": {
        "displayName": "Daily Cost Anomaly Alert",
        "scope": scope,
        "status": "Enabled",
        "schedule": {
            "frequency": "Daily",
            "hourOfDay": 8    # 8 AM UTC
        },
        "notification": {
            "to": [
                "cloudops@contoso.com",
                "finance@contoso.com"
            ],
            "subject": "Azure Cost Anomaly Detected — Action May Be Required"
        }
    }
}

resp = requests.put(url, headers=headers, json=body)
print(f"Anomaly alert created: {resp.status_code} — {resp.json().get('name')}")

# Create a credit alert at billing profile scope — fires when credit balance < 20%
billing_account_name = "<billing-account-id>"
billing_profile_name = "<billing-profile-id>"

import requests
from azure.identity import DefaultAzureCredential

credential = DefaultAzureCredential()
token = credential.get_token("https://management.azure.com/.default").token
headers = {
    "Authorization": f"Bearer {token}",
    "Content-Type": "application/json"
}

url = (
    f"https://management.azure.com/providers/Microsoft.Billing/"
    f"billingAccounts/{billing_account_name}/"
    f"billingProfiles/{billing_profile_name}/"
    f"providers/Microsoft.CostManagement/alerts/credit-low-20pct"
    f"?api-version=2023-11-01"
)

body = {
    "properties": {
        "definition": {
            "type": "Credit",
            "category": "Billing",
            "criteria": {
                "creditPercentage": 20   # fire when remaining credit < 20%
            }
        },
        "description": "Alert when Azure credit balance drops below 20%",
        "enabled": True,
        "contactEmails": [
            "finance@contoso.com",
            "cloud-ops@contoso.com"
        ]
    }
}

resp = requests.put(url, headers=headers, json=body)
print(f"Credit alert status: {resp.status_code}")

