import requests
import time
from azure.identity import DefaultAzureCredential

def setup_cost_governance_for_subscription(
    subscription_id: str,
    monthly_budget: float,
    alert_emails: list,
    anomaly_recipients: list
):
    """
    Provision cost governance for a newly created subscription:
    1. Monthly budget with three alert thresholds
    2. Daily anomaly alert
    Called from subscription vending pipeline.
    """
    credential = DefaultAzureCredential()
    token = credential.get_token("https://management.azure.com/.default").token
    headers = {
        "Authorization": f"Bearer {token}",
        "Content-Type": "application/json"
    }
    scope = f"/subscriptions/{subscription_id}"

    # 1. Create monthly budget
    budget_url = (
        f"https://management.azure.com{scope}/"
        f"providers/Microsoft.Consumption/budgets/monthly-budget"
        f"?api-version=2023-11-01"
    )
    budget_body = {
        "properties": {
            "category": "Cost",
            "amount": monthly_budget,
            "timeGrain": "Monthly",
            "timePeriod": {
                "startDate": "2024-01-01",
                "endDate": "2099-12-31"
            },
            "notifications": {
                "Actual_GT_80": {
                    "enabled": True,
                    "operator": "GreaterThan",
                    "threshold": 80,
                    "thresholdType": "Actual",
                    "contactEmails": alert_emails
                },
                "Actual_GT_95": {
                    "enabled": True,
                    "operator": "GreaterThan",
                    "threshold": 95,
                    "thresholdType": "Actual",
                    "contactEmails": alert_emails
                },
                "Forecasted_GT_100": {
                    "enabled": True,
                    "operator": "GreaterThan",
                    "threshold": 100,
                    "thresholdType": "Forecasted",
                    "contactEmails": alert_emails
                }
            }
        }
    }
    budget_resp = requests.put(budget_url, headers=headers, json=budget_body)
    print(f"Budget [{budget_resp.status_code}]: monthly-budget")

    time.sleep(2)

    # 2. Create anomaly alert
    anomaly_url = (
        f"https://management.azure.com{scope}/"
        f"providers/Microsoft.CostManagement/scheduledActions/anomaly-daily"
        f"?api-version=2023-11-01"
    )
    anomaly_body = {
        "kind": "InsightAlert",
        "properties": {
            "displayName": "Daily Cost Anomaly Alert",
            "scope": scope,
            "status": "Enabled",
            "schedule": {
                "frequency": "Daily",
                "hourOfDay": 8
            },
            "notification": {
                "to": anomaly_recipients,
                "subject": f"Cost Anomaly Detected in {subscription_id}"
            }
        }
    }
    anomaly_resp = requests.put(anomaly_url, headers=headers, json=anomaly_body)
    print(f"Anomaly alert [{anomaly_resp.status_code}]: anomaly-daily")

    return {
        "budget_status": budget_resp.status_code,
        "anomaly_status": anomaly_resp.status_code,
    }


result = setup_cost_governance_for_subscription(
    subscription_id="<new-subscription-id>",
    monthly_budget=5000.0,
    alert_emails=["finance@contoso.com", "cloudops@contoso.com"],
    anomaly_recipients=["cloudops@contoso.com"]
)
print("Governance provisioned:", result)
